import{_ as s,o as a,c as n,al as t}from"./chunks/framework.NffqDe-T.js";const u=JSON.parse('{"title":"Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1777224912000}'),o={name:"guide/index.md"};function i(l,e,r,p,d,c){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="guide" tabindex="-1">Guide <a class="header-anchor" href="#guide" aria-label="Permalink to &quot;Guide&quot;">​</a></h1><p>The guide section covers the concepts behind vuecs in depth. Read these once, and the rest of the docs will read more like a reference.</p><h2 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h2><ul><li><strong><a href="/guide/theme-system">Theme System</a></strong> — the four-layer class resolution chain (defaults → themes → overrides → instance props).</li><li><strong><a href="/guide/variants">Variants</a></strong> — structured variants, compound variants, and the merge rules across layers.</li><li><strong><a href="/guide/behavioral-defaults">Behavioral Defaults</a></strong> — the parallel resolution system for non-class props (button text, placeholders, content strings) — the i18n hook.</li><li><strong><a href="/guide/design-tokens">Design Tokens</a></strong> — <code>@vuecs/design</code>, the CSS custom-property layer underneath the class system.</li><li><strong><a href="/guide/navigation-manager">Navigation Manager</a></strong> — <code>@vuecs/navigation</code>&#39;s tree-state manager and how it integrates with <code>vue-router</code>.</li></ul><h2 id="mental-model" tabindex="-1">Mental model <a class="header-anchor" href="#mental-model" aria-label="Permalink to &quot;Mental model&quot;">​</a></h2><p>vuecs has three orthogonal systems that you configure independently in <code>app.use(vuecs, ...)</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─ themes/overrides ─────────────────────┐  → CSS class strings</span></span>
<span class="line"><span>│  layered resolution → class name(s)     │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span>┌─ defaults ─────────────────────────────┐  → behavioral values (text, booleans)</span></span>
<span class="line"><span>│  layered resolution → unwrapped value   │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span>┌─ design tokens (CSS variables) ────────┐  → concrete colors / radii</span></span>
<span class="line"><span>│  flip under .dark, swap via setPalette  │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼  components reference the first two via composables,</span></span>
<span class="line"><span>           the third via the class strings the first system produces</span></span></code></pre></div><p>Each system has its own composable: <code>useComponentTheme</code>, <code>useComponentDefaults</code>. The design-token layer needs no composable — it&#39;s pure CSS.</p>`,8)])])}const g=s(o,[["render",i]]);export{u as __pageData,g as default};
